mapper.update:
UPDATE t_tool_execution_journal
SET state = 'DISPATCHING',
    attempt = #{attempt},
    dispatched_at = #{dispatchedAt},
    updated_at = CURRENT_TIMESTAMP
WHERE execution_key = #{executionKey}
  AND state = #{expectedState}
  AND attempt = #{attempt}

UPDATE t_tool_execution_journal SET state = #{newState}, safe_error_code = #{safeErrorCode}, response_message_id =
CAST(#{responseMessageId} AS uuid) response_message_id , response_hash =
#{responseHash} response_hash , updated_at = CURRENT_TIMESTAMP WHERE execution_key = #{executionKey} AND state = #{expectedState} AND attempt = #{expectedAttempt}

UPDATE t_tool_execution_journal
SET state = 'BLOCKED',
    safe_error_code = 'DEADLINE_EXCEEDED_PREPARED',
    updated_at = CURRENT_TIMESTAMP
WHERE id IN (
    SELECT id FROM t_tool_execution_journal
    WHERE state = 'PREPARED'
      AND updated_at < #{cutoff}
    LIMIT #{batchLimit}
)

UPDATE t_tool_execution_journal
SET state = 'OUTCOME_UNKNOWN',
    safe_error_code = 'DEADLINE_EXCEEDED_DISPATCHING',
    updated_at = CURRENT_TIMESTAMP
WHERE id IN (
    SELECT id FROM t_tool_execution_journal
    WHERE state = 'DISPATCHING'
      AND dispatched_at < #{cutoff}
    LIMIT #{batchLimit}
)

mapper.delete:
DELETE FROM t_tool_execution_journal
WHERE id IN (
    SELECT id FROM t_tool_execution_journal
    WHERE (
        (state IN ('SUCCEEDED', 'FAILED_KNOWN', 'BLOCKED') AND updated_at < #{retainedCutoff})
        OR
        (state = 'OUTCOME_UNKNOWN' AND updated_at < #{unknownCutoff})
    )
    LIMIT #{batchLimit}
)
